{
  "terms": [
    {
      "term": "Ammeter",
      "simpleDefinition": "An instrument used to measure the flow of electric current in a circuit.",
      "anchor": "Think of an ammeter as a flow meter for electrons.",
      "misconception": "Believing an ammeter measures electrical pressure rather than flow."
    },
    {
      "term": "Voltmeter",
      "simpleDefinition": "An instrument used to measure the electrical potential difference (voltage) between two points.",
      "anchor": "Use a voltmeter to check the 'push' or pressure in the circuit.",
      "misconception": "Thinking a voltmeter must be connected in the same way as an ammeter."
    },
    {
      "term": "Ohmmeter",
      "simpleDefinition": "An instrument used to measure the resistance or opposition to current flow in a circuit.",
      "anchor": "An ohmmeter checks if a path is clear or blocked by measuring its resistance.",
      "misconception": "Assuming a standard low-voltage ohmmeter is sufficient for testing cable insulation safety."
    },
    {
      "term": "Insulation Resistance Tester",
      "simpleDefinition": "A high-voltage instrument used to test the integrity of cable insulation to ensure no current leaks.",
      "anchor": "The specialist tool used to find tiny leaks in the protective coating of wires.",
      "misconception": "Confusing a basic continuity tester with a high-voltage insulation tester."
    },
    {
      "term": "Wattmeter",
      "simpleDefinition": "An instrument used to measure the rate of electrical power being used at a specific moment.",
      "anchor": "A wattmeter shows how much work an appliance is doing right now.",
      "misconception": "Confusing the rate of power (Watts) with the total energy used over time (Joules)."
    },
    {
      "term": "Energy Meter",
      "simpleDefinition": "An instrument that measures the total amount of electrical energy consumed over a period of time.",
      "anchor": "The meter used by electricity suppliers to calculate your bill based on total usage.",
      "misconception": "Thinking an energy meter and a wattmeter measure the exact same thing."
    }
  ],
  "anchorPhrases": [
    "Ammeter for current",
    "Voltmeter for voltage",
    "Ohmmeter for resistance",
    "Wattmeter for power",
    "Energy meter for total consumption",
    "Insulation resistance tester for safety checks"
  ],
  "misconceptionTargets": [
    "Using the term 'multimeter' when a specific instrument like an 'Ammeter' is required.",
    "Believing a standard ohmmeter can be used to verify insulation integrity.",
    "Confusing the instantaneous measurement of a Wattmeter with the cumulative measurement of an Energy Meter.",
    "Using vague terms like 'tester' instead of technically precise instrument names."
  ]
}

