    {
      "title": "Measuring Voltage and Current",
      "basicQuestions": [
        {
          "questionText": "Which specific instrument is used to measure the electrical potential difference between two points?",
          "answerGuidance": [
            "Voltmeter",
            "A voltmeter"
          ]
        },
        {
          "questionText": "What is the name of the instrument used to measure the flow of electrons through a conductor?",
          "answerGuidance": [
            "Ammeter",
            "An ammeter"
          ]
        },
        {
          "questionText": "What electrical quantity is being measured when an electrician uses an Ammeter?",
          "answerGuidance": [
            "Current",
            "Electrical current"
          ]
        }
      ],
      "deeperQuestionText": "Why is it technically important that an Ammeter has very low resistance while a Voltmeter has high resistance?",
      "deeperAnswerGuidance": [
        "An ammeter must not block the flow it is measuring",
        "Low resistance prevents the ammeter from restricting current",
        "A voltmeter must not draw current away from the circuit",
        "High resistance ensures the voltmeter does not change the circuit conditions"
      ],
      "hint": "Think of 'V' for Voltmeter and 'A' for Ammeter."
    },
    {
      "title": "Measuring Resistance",
      "basicQuestions": [
        {
          "questionText": "Which instrument is used for standard tasks such as checking the continuity of a wire?",
          "answerGuidance": [
            "Ohmmeter",
            "An ohmmeter"
          ]
        },
        {
          "questionText": "What specialist tool is required to verify the safety and integrity of cable coatings?",
          "answerGuidance": [
            "Insulation Resistance Tester",
            "Insulation tester"
          ]
        },
        {
          "questionText": "What specific property of a circuit is an Ohmmeter designed to measure?",
          "answerGuidance": [
            "Resistance",
            "Opposition to current flow"
          ]
        }
      ],
      "deeperQuestionText": "Why can a standard battery-powered Ohmmeter not be used to reliably test cable insulation safety?",
      "deeperAnswerGuidance": [
        "Standard ohmmeters use low voltage that cannot detect tiny cracks",
        "Insulation needs high voltage to stress the material",
        "Low voltage will not force current through small leakage paths",
        "High pressure is needed to find weak spots in the insulation"
      ],
      "hint": "Standard resistance uses an Ohmmeter, but safety checks on cable coatings need a high-voltage tester."
    },
    {
      "title": "Measuring Power and Energy",
      "basicQuestions": [
        {
          "questionText": "Which instrument measures the instantaneous rate at which an appliance is doing work?",
          "answerGuidance": [
            "Wattmeter",
            "A wattmeter"
          ]
        },
        {
          "questionText": "What is the name of the meter used to measure the total amount of electrical work done over a period of time?",
          "answerGuidance": [
            "Energy Meter",
            "Kilowatt-hour meter",
            "kWh meter"
          ]
        },
        {
          "questionText": "What electrical quantity is identified by a Wattmeter reading?",
          "answerGuidance": [
            "Power",
            "Electrical power"
          ]
        }
      ],
      "deeperQuestionText": "Using the car analogy from the text, how does the function of an Energy Meter differ from that of a Wattmeter?",
      "deeperAnswerGuidance": [
        "A wattmeter is like a speedometer showing speed at one moment",
        "An energy meter is like an odometer showing total distance",
        "The wattmeter measures a rate while the energy meter measures a total",
        "Energy meters track cumulative consumption over time"
      ],
      "hint": "Power is a moment in time (Watts); Energy is the total used over time (kWh)."
    },
    {
      "title": "Instrument Selection Summary",
      "basicQuestions": [
        {
          "questionText": "According to technical standards, what specific instrument must be used to measure electrical pressure?",
          "answerGuidance": [
            "Voltmeter",
            "A voltmeter"
          ]
        },
        {
          "questionText": "Which instrument should be selected to measure the opposition to current flow in a circuit?",
          "answerGuidance": [
            "Ohmmeter",
            "An ohmmeter"
          ]
        },
        {
          "questionText": "What is the correct technical name for the instrument that measures total electrical consumption for billing?",
          "answerGuidance": [
            "Energy Meter",
            "Kilowatt-hour meter"
          ]
        }
      ],
      "deeperQuestionText": "Why is it critical to use technically precise names like 'Ammeter' rather than vague terms like 'tester' when selecting equipment?",
      "deeperAnswerGuidance": [
        "Each instrument is designed for a specific physical property",
        "Vague terms can lead to selecting the wrong tool for the quantity",
        "Using the wrong meter can cause damage to the instrument",
        "Precise names ensure clear communication and safety on-site"
      ],
      "hint": "Match the quantity to the meter: Voltage-Voltmeter, Current-Ammeter, Resistance-Ohmmeter, Power-Wattmeter, Energy-Energy Meter."
    }
  ]
}

